/**
 * S2 — OTP Verify (login storm).
 * Uses OTPs pre-generated by run.sh and stored in .otps.json.
 * If .otps.json is empty (standalone run), falls back to testing the
 * token refresh endpoint to still exercise the auth path.
 * Expected: 200 with access_token.
 */
import http from 'k6/http';
import { sleep } from 'k6';
import { BASE_URL, writeParams } from '../k6.config.js';
import { assertResponse, randomSleep } from '../lib/checks.js';
import { getOTP, getAuth } from '../lib/auth.js';
import { newIdempotencyKey } from '../lib/idempotency.js';

export function otpVerifyTest() {
  const otp = getOTP();

  if (otp) {
    // Fresh OTP available: test the full verify endpoint.
    const res = http.post(
      `${BASE_URL}/auth/otp/verify`,
      JSON.stringify({ phone: otp.phone, code: otp.code, purpose: 'login' }),
      writeParams(null, newIdempotencyKey()),
    );
    assertResponse(res, 200, 'otp-verify', (b) => typeof b.access_token === 'string');
  } else {
    // Fallback: test the token refresh endpoint with a valid token.
    // This exercises the same JWT verification middleware path.
    const { token } = getAuth();
    const res = http.get(
      `${BASE_URL}/me`,
      { headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/json' }, tags: { type: 'read' } },
    );
    // 200 means token valid; 401 means expired (setup.sh needs re-run).
    assertResponse(res, 200, 'otp-verify-fallback-me');
  }

  sleep(randomSleep());
}
